<?php
session_start();
require_once 'includes/db.php';
if (!isset($_SESSION['user_id']) || $_SESSION['user_role'] !== 'student') { header('Location: login.php'); exit; }

$pdo = getDB();
$userId = $_SESSION['user_id'];

// Handle Payment Submission
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $reqId = $_POST['request_id'];
    $method = $_POST['method'];
    $trxRef = $_POST['generated_ref']; // Recieved from the hidden input
    
    try {
        $pdo->beginTransaction();

        // 1. Insert into payments table using the reference generated by the student's browser
        $stmt = $pdo->prepare("INSERT INTO payments (request_id, amount, payment_method, transaction_reference, status) 
                               SELECT id, total_amount, ?, ?, 'pending' FROM requests WHERE id = ?");
        $stmt->execute([$method, $trxRef, $reqId]);

        // 2. Mark request as 'paid' status and notify admin
        $pdo->prepare("UPDATE requests SET status = 'paid', is_viewed = FALSE WHERE id = ?")->execute([$reqId]);

        $pdo->commit();
        $success = "Payment details submitted! Transaction Ref: <strong>$trxRef</strong>";
    } catch (Exception $e) {
        $pdo->rollBack();
        $error = "Payment failed: " . $e->getMessage();
    }
}

// Fetch requests that are NOT yet released
$requests = $pdo->prepare("SELECT r.*, dt.name as document_name FROM requests r 
                           JOIN document_types dt ON r.document_type_id = dt.id 
                           WHERE r.user_id = ? AND r.status IN ('pending', 'paid', 'approved') 
                           ORDER BY r.created_at DESC");
$requests->execute([$userId]);
$rows = $requests->fetchAll();
?>
