<script>
// Logic to generate TRX ID instantly
function generateTransactionID() {
    const now = new Date();
    const datePart = now.getFullYear() + 
                     String(now.getMonth() + 1).padStart(2, '0') + 
                     String(now.getDate()).padStart(2, '0');
    
    // Generate 8 random uppercase characters/numbers
    const randomPart = Math.random().toString(36).substring(2, 10).toUpperCase();
    
    return `TRX-${datePart}-${randomPart}`;
}

function openPay(id, doc, amt) {
    // 1. Set basic details
    document.getElementById('pay_req_id').value = id;
    document.getElementById('display_doc').innerText = doc;
    document.getElementById('display_amt').innerText = '₱' + parseFloat(amt).toFixed(2);
    
    // 2. GENERATE ID IMMEDIATELY
    const newTrxID = generateTransactionID();
    
    // 3. SHOW ID IN UI AND SET IN HIDDEN FIELD
    document.getElementById('display_trx').innerText = newTrxID;
    document.getElementById('hidden_trx_ref').value = newTrxID;
    
    // 4. Open Modal
    document.getElementById('payModal').classList.add('open');
}

function closePay() { document.getElementById('payModal').classList.remove('open'); }

window.onclick = function(event) {
    if (event.target == document.getElementById('payModal')) closePay();
}
</script>

